# ==============================================================
#  ShowAlert.ps1  –  SELF-CONTAINED, no extra files needed
# ==============================================================
#
#  HOW TO CUSTOMISE
#  ----------------
#  1. Get Base64 of YOUR image (JPG/PNG/BMP):
#       [Convert]::ToBase64String([IO.File]::ReadAllBytes("C:\path\to\image.jpg"))
#     Copy the output and paste it as the value of $IMAGE_B64 below.
#
#  2. Get Base64 of YOUR sound (WAV):
#       [Convert]::ToBase64String([IO.File]::ReadAllBytes("C:\path\to\sound.wav"))
#     Copy the output and paste it as the value of $SOUND_B64 below.
#
#  3. Run:
#       powershell -ExecutionPolicy Bypass -File ShowAlert.ps1
#
#  Currently uses a placeholder red-square image and silent WAV.
# ==============================================================

# ── SETTINGS ──────────────────────────────────────────────────
$DelaySeconds   = 30   # seconds to wait before showing
$DisplaySeconds = 30   # seconds to show image/play sound
$ImageExt       = "bmp" # extension that matches your embedded image (jpg/png/bmp)
$SoundExt       = "mp3" # extension that matches your embedded sound (wav/mp3/m4a etc)

# ── EMBEDDED IMAGE (Base64) ────────────────────────────────────
$IMAGE_B64 = ''

# ── EMBEDDED SOUND (Base64 WAV) ───────────────────────────────
$SOUND_B64 = ''

# ==============================================================
#  Everything below this line runs automatically
# ==============================================================

Add-Type -AssemblyName System.Windows.Forms
Add-Type -AssemblyName System.Drawing

# ── Win32: ClipCursor ─────────────────────────────────────────
Add-Type @"
using System;
using System.Runtime.InteropServices;
public class Win32Cursor {
    [DllImport("user32.dll")]
    public static extern bool ClipCursor(ref RECT r);
    [DllImport("user32.dll")]
    public static extern bool ClipCursor(IntPtr r);
    [StructLayout(LayoutKind.Sequential)]
    public struct RECT { public int Left, Top, Right, Bottom; }
}
"@

# ── COM Audio API: set master volume ──────────────────────────
Add-Type @"
using System.Runtime.InteropServices;
[Guid("5CDF2C82-841E-4546-9722-0CF74078229A"),InterfaceType(ComInterfaceType.InterfaceIsIUnknown)]
interface IAudioEndpointVolume {
    int _1();int _2();int _3();int _4();
    int SetMasterVolumeLevelScalar(float f, System.Guid g);
    int _6();
    int GetMasterVolumeLevelScalar(out float f);
    int SetMute([MarshalAs(UnmanagedType.Bool)]bool b, System.Guid g);
    int GetMute(out bool b);
}
[Guid("D666063F-1587-4E43-81F1-B948E807363F"),InterfaceType(ComInterfaceType.InterfaceIsIUnknown)]
interface IMMDevice {
    int Activate(ref System.Guid id,int ctx,int p,[MarshalAs(UnmanagedType.IUnknown)]out object o);
}
[Guid("A95664D2-9614-4F35-A746-DE8DB63617E6"),InterfaceType(ComInterfaceType.InterfaceIsIUnknown)]
interface IMMDeviceEnumerator {
    int _1();
    int GetDefaultAudioEndpoint(int flow,int role,out IMMDevice d);
}
[ComImport,Guid("BCDE0395-E52F-467C-8E3D-C4579291692E")]
class MMDeviceEnumeratorComObject {}
public class VolumeHelper {
    public static void SetMax() {
        var e=(IMMDeviceEnumerator)new MMDeviceEnumeratorComObject();
        IMMDevice d; e.GetDefaultAudioEndpoint(0,1,out d);
        var iid=new System.Guid("5CDF2C82-841E-4546-9722-0CF74078229A");
        object v; d.Activate(ref iid,23,0,out v);
        var ep=(IAudioEndpointVolume)v;
        ep.SetMasterVolumeLevelScalar(1.0f,System.Guid.Empty);
        ep.SetMute(false,System.Guid.Empty);
    }
}
"@

# ── 1. Decode embedded files to TEMP ──────────────────────────
$tmpImg   = [IO.Path]::Combine([IO.Path]::GetTempPath(), "alert_img.$ImageExt")
$tmpSound = [IO.Path]::Combine([IO.Path]::GetTempPath(), "alert_snd.$SoundExt")

[IO.File]::WriteAllBytes($tmpImg,   [Convert]::FromBase64String($IMAGE_B64))
[IO.File]::WriteAllBytes($tmpSound, [Convert]::FromBase64String($SOUND_B64))

# ── 2. Wait ────────────────────────────────────────────────────
Start-Sleep -Seconds $DelaySeconds

# ── 3. Volume to 100% ─────────────────────────────────────────
try { [VolumeHelper]::SetMax() } catch { Write-Warning "Volume failed: $_" }

# ── 4. Build fullscreen form ───────────────────────────────────
$form = New-Object System.Windows.Forms.Form
$form.Text            = ""
$form.FormBorderStyle = [System.Windows.Forms.FormBorderStyle]::None
$form.WindowState     = [System.Windows.Forms.FormWindowState]::Maximized
$form.TopMost         = $true
$form.BackColor       = [System.Drawing.Color]::Black
$form.Cursor          = [System.Windows.Forms.Cursors]::None

$pb           = New-Object System.Windows.Forms.PictureBox
$pb.Dock      = [System.Windows.Forms.DockStyle]::Fill
$pb.SizeMode  = [System.Windows.Forms.PictureBoxSizeMode]::StretchImage
$pb.Image     = [System.Drawing.Image]::FromFile($tmpImg)
$form.Controls.Add($pb)

# ── 5. Play sound looping ─────────────────────────────────────
$player = New-Object System.Media.SoundPlayer($tmpSound)
$player.PlayLooping()

# ── 6. Lock mouse to primary screen ───────────────────────────
$bounds = [System.Windows.Forms.Screen]::PrimaryScreen.Bounds
$rect   = New-Object Win32Cursor+RECT
$rect.Left=$bounds.Left; $rect.Top=$bounds.Top
$rect.Right=$bounds.Right; $rect.Bottom=$bounds.Bottom
[Win32Cursor]::ClipCursor([ref]$rect) | Out-Null

# ── 7. Block keyboard & prevent manual close ─────────────────
$script:allowClose = $false

$form.KeyPreview = $true
$form.Add_KeyDown({
    $_.SuppressKeyPress = $true
    $_.Handled = $true
})

$form.Add_FormClosing({
    if (-not $script:allowClose) {
        $_.Cancel = $true
    }
})

# ── 8. Auto-close timer (10 seconds) ─────────────────────────
$timer          = New-Object System.Windows.Forms.Timer
$timer.Interval = 10 * 1000
$timer.Add_Tick({
    $timer.Stop()
    $script:allowClose = $true
    $form.Close()
})
$timer.Start()

# ── 9. Run (blocks here until timer fires) ────────────────────
[System.Windows.Forms.Application]::Run($form)

# ── 10. Cleanup ───────────────────────────────────────────────
$player.Stop()
[Win32Cursor]::ClipCursor([System.IntPtr]::Zero) | Out-Null
$pb.Image.Dispose()
Remove-Item $tmpImg   -Force -ErrorAction SilentlyContinue
Remove-Item $tmpSound -Force -ErrorAction SilentlyContinue
